sp_widget.client_script:
api.controller=function($rootScope, $scope, $timeout, $sce, spUtil, $log, $location, i18n) {
  /* widget controller */
  var c = this;
	$scope.dtech_tasker_common = x_153465_discovert.dtech_tasker_common;
	var shared = {};
	var tasker_app_base_wp = {
		// TODO - ADD CORE PARAMETERS HERE
		// not sure if we need any params
		shared: shared
	};
	c.data.leftPanel = [];
	c.data.righPanel = [];
	main();

	function main(){
		_setBodyContainerVariables();
	}

	// when loading wait for the page to load, then set split based on parent left nav
	$scope.$watch('$viewContentLoaded', function(){
		_setSplitPanelWidth($scope.$parent.$parent.leftNavigationWidth);
	});

	// may need to process this to determine where coming from and react accodingly
	$scope.$on('data_table.click', function(e, parms) {
		if(c.data.home){
			if(c.data.sys_id != parms.sys_id){
				c.data.popout = true;
			} else {
				// for now toggle popout, later may do mroe
				c.data.popout = !c.data.popout;
			}
			c.data.sys_id = parms.sys_id;
		}
	});

	c.widget.changeAppContext=function(context){
		c.data.appContext=context;
		_updateConextData();
		_setBodyContainerVariables();
		// context changed update the width based on what is open
		_setSplitPanelWidth($scope.$parent.$parent.leftNavigationWidth);
	};

	// this is run when navigation panel is toggled.
	c.widget.toggleNavigationWidth = function(leftNavWidth){
		_setSplitPanelWidth(leftNavWidth);
	}

	$scope.changeScreenSetting= function(setFullScreen){
		$scope.fullScreen = setFullScreen;
		_setScreenSetting();
	};

	function loadHomePortal(){
		var tasker_portal_board_with_filter_wp = {
			bifold:true,
			show_keywords:true,
			show_breadcrumbs:true,
			enable_filter:true,
			window_size:10,
			// not sure if we need any params
			shared: shared
		};
		c.data.tasker_portal_board_with_filters = [];

		spUtil.get('tasker_portal_board_with_filter', tasker_portal_board_with_filter_wp).then(function(response){
			var tasker_portal_board_with_filter_widget = response;
			c.data.tasker_portal_board_with_filters.push(tasker_portal_board_with_filter_widget);
		});
	}

	function _updateConextData(){
		switch (c.data.appContext){
			case $scope.dtech_tasker_common.CONSTANTS.APP_CONTEXTS.ORGANIZATION:
				c.data.table = $scope.dtech_tasker_common.CONSTANTS.TABLES.TABLE_NAME_ORGANIZATIONAL_HIERARCHY;
				break;
			case $scope.dtech_tasker_common.CONSTANTS.APP_CONTEXTS.TASK:
				c.data.table = $scope.dtech_tasker_common.CONSTANTS.TABLES.TABLE_NAME_TASK;
				break;
			case $scope.dtech_tasker_common.CONSTANTS.APP_CONTEXTS.TEMPLATE:
				c.data.table = $scope.dtech_tasker_common.CONSTANTS.TABLES.TABLE_NAME_TEMPLATE;
				break;
		}
	}

	function _setBodyContainerVariables(){
		c.data.home =
			(c.data.appContext==$scope.dtech_tasker_common.CONSTANTS.APP_CONTEXTS.HOME ||
			c.data.appContext==$scope.dtech_tasker_common.CONSTANTS.APP_CONTEXTS.HOME_FILTER);

		// todo, get full screen based on context and user preferences
		$scope.fullScreen=_getScreenSetting();

		// reset poput to false
		c.data.popout=false;

		// TODO - consider only loading at the start
		// this should be based on how much load it puts on system to keep loaded
		if(c.data.home==true){
			loadHomePortal();
		} else {
			_loadLeftPanel();
			_loadRightPanel();
		}
	}

	function _getScreenSetting(){
		var fullScreen=true;
		switch (c.data.appContext){
			case $scope.dtech_tasker_common.CONSTANTS.APP_CONTEXTS.ORGANIZATION:
				fullScreen = c.data.appPreferences.organizationFullScreen;
				break;
			case $scope.dtech_tasker_common.CONSTANTS.APP_CONTEXTS.TASK:
				fullScreen = c.data.appPreferences.taskFullScreen;
				break;
			case $scope.dtech_tasker_common.CONSTANTS.APP_CONTEXTS.TEMPLATE:
				fullScreen = c.data.appPreferences.templateFullScreen;
				break;
		}
		return fullScreen;
	}

	function _setSplitPanelWidth(leftNavWidth){
		var numToSubtract = leftNavWidth;
		if(c.data.popout){
			var popupPanelDiv = angular.element(document.getElementById('tasker_app_popup_panel'))[0];
			numToSubtract = numToSubtract + popupPanelDiv.clientWidth;
		}
		// calulate the width as 50% of space remaining without left nav and popup
		var halfNumberToSubtract = numToSubtract / 2 + "px";
		numToSubtract = numToSubtract + "px";
		if(c.data.home){
			var homePanelDiv = angular.element(document.getElementById('tasker_app_home_panel'))[0];
			homePanelDiv.style.setProperty("width","calc(100vh - " + numToSubtract + ")");
		} else {
			// Get left and right panels by id
			var leftPanelDiv = angular.element(document.getElementById('tasker_app_left_panel'))[0];
			// use Nav Width and popup hover on to remove left and right spacing
			if($scope.fullScreen){
				leftPanelDiv.style.setProperty("width", "calc(100vw - " + numToSubtract + ")");
			} else { // split screen
				var rightPanelDiv = angular.element(document.getElementById('tasker_app_right_panel'))[0];
				leftPanelDiv.style.setProperty("width", "calc(50vw - " + halfNumberToSubtract + ")");
				rightPanelDiv.style.setProperty("width", "calc(50vw - " + halfNumberToSubtract + ")");
			}
		}	
	}

// TODO - May want to save newValue / old value
// this way when we get back to the server we can process just the chnanged values
	function _setScreenSetting(){
		switch (c.data.appContext){
			case $scope.dtech_tasker_common.CONSTANTS.APP_CONTEXTS.ORGANIZATION:
				c.data.appPreferences.organizationFullScreen=$scope.fullScreen;
				break;
			case $scope.dtech_tasker_common.CONSTANTS.APP_CONTEXTS.TASK:
				c.data.appPreferences.taskFullScreen=$scope.fullScreen;
				break;
			case $scope.dtech_tasker_common.CONSTANTS.APP_CONTEXTS.TEMPLATE:
				c.data.appPreferences.templateFullScreen = $scope.fullScreen;
				break;
		}		
// TODO - POST save back to user prefernces back to the 
	}

	function _loadLeftPanel(){
		var leftPanel={};
		switch (c.data.appContext){
			case $scope.dtech_tasker_common.CONSTANTS.APP_CONTEXTS.ORGANIZATION:
				leftPanel.widgetType = c.data.appPreferences.organizationLeftPanel;
// force tree for now, build constants later
				leftPanel.widgetId="discovertasker-officehierarchy";
				leftPanel.widgetParams = {bifold:true, table: c.data.table, embeddedWidget:true};
				break;
			case $scope.dtech_tasker_common.CONSTANTS.APP_CONTEXTS.TASK:
				leftPanel.widgetType = c.data.appPreferences.taskLeftPanel;
// force tree for now, build constants later
				leftPanel.widgetId="discovertasker-recursivetasktreegraph";
// TODO - figure out how to change topstickabsolute off when in this mode and 3 column , hide_accordion:true
				leftPanel.widgetParams = {bifold:true, table:c.data.table, hide_accordion:true, embeddedWidget:true};
				break;
			case $scope.dtech_tasker_common.CONSTANTS.APP_CONTEXTS.TEMPLATE:
// discovertasker-listtabbed

				leftPanel.widgetType = c.data.appPreferences.templateLeftPanel;
// force tree for now, build constants later
				leftPanel.widgetId="discovertasker-listtabbed";
				leftPanel.widgetParams = {bifold:true, table:c.data.table, embeddedWidget:true};
				break;
		}
		c.data.leftPanel=[]; // clear array
		_loadWidget(leftPanel.widgetId, c.data.leftPanel, leftPanel.widgetParams, _setLeftPanelCallBack);
	}

	function _setLeftPanelCallBack(widget){
		c.data.leftPanel.push(widget);		
	}

	// if this is all we are doing, then maybe we could just pass array
	function _setRightPanelCallBack(widget){
		c.data.rightPanel.push(widget);		
	}


	// TODO, think about how this could be done with one function instead of 2
	function _loadRightPanel(){
		var rightPanel={};
		switch (c.data.appContext){
			case $scope.dtech_tasker_common.CONSTANTS.APP_CONTEXTS.ORGANIZATION:
				rightPanel.widgetType = c.data.appPreferences.templateRightPanel;
// force tree for now, build constants later
				rightPanel.widgetId="tasker_form_v3";
				rightPanel.widgetParams = {bifold:true, embeddedWidget:true, 
																	 table: c.data.table};
				break;
			case $scope.dtech_tasker_common.CONSTANTS.APP_CONTEXTS.TASK:
				rightPanel.widgetId="tasker_form_v3";
				rightPanel.widgetParams = {bifold:false, embeddedWidget:true, 
																	 table: c.data.table};
				break;
			case $scope.dtech_tasker_common.CONSTANTS.APP_CONTEXTS.TEMPLATE:
// force tab list at start, build constants later
				rightPanel.widgetType = c.data.appPreferences.templateRightPanel;
// force tree for now, build constants later
				rightPanel.widgetId="discovertasker-processtemplatetreegraph";
				rightPanel.widgetParams = {bifold:true, embeddedWidget:true, 
																	 table: $scope.dtech_tasker_common.CONSTANTS.TABLES.TABLE_NAME_TEMPLATE_TASK};

				break;
		}
		if(rightPanel.widgetId){
			c.data.rightPanel=[]; // clear array
			_loadWidget(rightPanel.widgetId, c.data.rightPanel, rightPanel.widgetParams, _setRightPanelCallBack);
		}
	}

// add widget specific parameter functions
// tree, list, gantt, card, form
	function _loadWidget(widgetId, widgetArray, widgetParams, callBack){
		spUtil.get(widgetId, widgetParams).then(callBack);
	}
};

