// WIDGET BASE: Tasker App Body Container
// COMPANY: Discover Technologies
(function($sp, input, data, options, gs) {
  /* populate the 'data' object */
  /* e.g., data.table = $sp.getValue('table'); */
	main();

	function main(){
		data.appContext = (input || {}).appContext || (options || {}).appContext || "";
		data.appPreferences = (input || {}).appPreferences || (options || {}).appPreferences || undefined;		
		data.table = (input || {}).table || (options || {}).table || $sp.getParameter("table") || "";
		data.sys_id = (input || {}).sys_id || (options || {}).sys_id || $sp.getParameter("sys_id") || $sp.getParameter("sl_sys_id");
	}


})($sp, input, data, options, gs);
